Steps:
[AUTH role=ORG_USER]
[GQL-OP setup_me]
  query { me { id } }
[GQL-EXEC setup_me]
[GQL-CAPTURE setup_me.data.me.id → USER_ID]
[GQL-OP get_cart]
  query {
    cart(storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" currencyCode: "USD" cultureName: "en-US") {
      id name itemsCount
      items { id productId quantity }
    }
  }
[GQL-EXEC get_cart]
[GQL-CAPTURE get_cart.data.cart.id → CART_ID]

[AUTH role=ORG_USER]
[GQL-OP setup_me]
  query { me { id } }
[GQL-EXEC setup_me]
[GQL-CAPTURE setup_me.data.me.id → USER_ID]
[GQL-OP setup_prod]
  query { products(storeId: "{{STORE_ID}}" currencyCode: "USD" first: 1 filter: "category.subtree:fc596540864a41bf8ab78734ee7353a3 price.USD:(0 TO) inStock_variations:true") { items { id } } }
[GQL-EXEC setup_prod]
[GQL-CAPTURE setup_prod.data.products.items.0.id → PRODUCT_ID]
[GQL-OP pre_clear]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id itemsCount } }
[GQL-EXEC pre_clear]
[GQL-OP add_one]
  mutation {
    addItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" productId: "{{PRODUCT_ID}}" quantity: 2 }) {
      id itemsCount items { id productId quantity listPrice { amount } }
    }
  }
[GQL-EXEC add_one]
[GQL-OP cleanup_clear]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id itemsCount } }
[GQL-EXEC cleanup_clear]

