[GQL-EXEC add_item]
[GQL-CAPTURE add_item.data.addItem.items.0.id → LINE_ITEM_ID]
[GQL-OP change_qty]
  mutation {
    changeCartItemQuantity(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" lineItemId: "{{LINE_ITEM_ID}}" quantity: 5 }) {
      id items { id quantity } subTotal { amount }
    }
  }
[GQL-EXEC change_qty]
[GQL-OP cleanup_clear]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC cleanup_clear]

